function applyPostFixes(text) {
  let value = String(text);
  for (const [from, to] of POST_FIXES) {
    value = value.split(from).join(to);
  }
  return value;
}

export function rusifyNextAction(nextAction, workId) {
  const raw = String(nextAction ?? '').trim();
  if (raw === '' || raw === '—') {
    return raw;
  }
  if (NEXT_ACTION_MAP[raw]) {
    return NEXT_ACTION_MAP[raw];
  }
  if (/^review and promote/i.test(raw)) {
    return 'просмотреть и перевести в ready';
  }
  if (/^[a-z0-9-]+$/u.test(raw) && raw.includes('-')) {
    return rusifyLine(raw.replace(/-/gu, ' '));
  }
  return rusifyLine(raw);
}

const TITLE_OVERRIDES = {
  'design-draft-store-backlog-intake': 'спроектировать приём черновиков в бэклог',
  'implement-semantic-map-ui-cross-highlight': 'реализовать перекрёстную подсветку semantic map ↔ бэклог',
  'implement-workgraph-mcp-server-mvp': 'реализовать MVP MCP-сервера Work Graph',
};

export function rusifyTitle(title, workId) {
  if (TITLE_OVERRIDES[workId]) {
    return TITLE_OVERRIDES[workId];
  }
  const raw = String(title ?? workId ?? '').trim();
  const rusified = rusifyLine(raw);
  if (/^[a-z]/u.test(rusified) && workId) {
    const [prefix] = workId.split('-');
    const ruPrefix = TITLE_PREFIX[prefix];
    if (ruPrefix) {
      const tail = workId.slice(prefix.length + 1).replace(/-/gu, ' ');
      return `${ruPrefix} ${rusifyLine(tail)}`.replace(/\s{2,}/gu, ' ').trim();
    }
  }
  return rusified;
}

export function rusifyStringList(values) {
  if (!Array.isArray(values)) {
    return values;
  }
  return values
    .flatMap((line) => String(line).split(/\n+/u).map((part) => rusifyLine(part.trim())).filter(Boolean))
    .filter(Boolean);
}

export function rusifyWorkItemFields(item) {
  return {
    basis: rusifyStringList(Array.isArray(item.basis) ? item.basis : [item.basis].filter(Boolean)),
    vector: rusifyStringList(Array.isArray(item.vector) ? item.vector : [item.vector].filter(Boolean)),
    goal: rusifyStringList(Array.isArray(item.goal) ? item.goal : [item.goal].filter(Boolean)),
    checks: item.checks ? rusifyStringList(item.checks) : undefined,
    evidence: item.evidence,
    title: rusifyTitle(item.title, item.id),
    nextAction: rusifyNextAction(item.nextAction, item.id),
  };
}

